'use client'
import { useState } from 'react'
import { signIn, getSession } from 'next-auth/react'
import { useRouter } from 'next/navigation'

export default function LoginPage() {
  const router = useRouter()
  const [form, setForm] = useState({ email: '', password: '' })
  const [error, setError] = useState('')
  const [loading, setLoading] = useState(false)

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setError('')

    const res = await signIn('credentials', {
      email: form.email,
      password: form.password,
      redirect: false,
    })

    setLoading(false)
    if (res?.error) {
      setError('Invalid email or password.')
    } else {
      const session = await getSession()
      const role = (session?.user as any)?.role
      if (role === 'SUPER_ADMIN')  router.push('/super-admin')
      else if (role === 'TENANT_ADMIN') router.push('/tenant-admin')
      else if (role === 'IT_AGENT')     router.push('/dashboard')
      else                              router.push('/portal')
    }
  }

  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #0F172A 0%, #1E3A5F 100%)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontFamily: 'Georgia, serif' }}>
      <div style={{ width: 420, background: 'white', borderRadius: 20, padding: 40, boxShadow: '0 24px 64px rgba(0,0,0,0.3)' }}>
        <div style={{ textAlign: 'center', marginBottom: 32 }}>
          <div style={{ fontSize: 32, fontWeight: 900, color: '#0F172A', marginBottom: 4 }}>
            Edu<span style={{ color: '#2563EB' }}>Desk</span>
          </div>
          <div style={{ fontSize: 13, color: '#94A3B8', fontFamily: 'monospace' }}>UNIVERSITY HELPDESK</div>
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: 16 }}>
            <label style={{ display: 'block', fontSize: 11, fontFamily: 'monospace', color: '#64748B', marginBottom: 6 }}>EMAIL ADDRESS</label>
            <input
              type="email"
              value={form.email}
              onChange={e => setForm({ ...form, email: e.target.value })}
              placeholder=""
              autoComplete="username"
              required
              style={{ width: '100%', padding: '12px 14px', border: '1px solid #E2E8F0', borderRadius: 10, fontSize: 14, fontFamily: 'Georgia, serif', outline: 'none', boxSizing: 'border-box' }}
            />
          </div>

          <div style={{ marginBottom: 24 }}>
            <label style={{ display: 'block', fontSize: 11, fontFamily: 'monospace', color: '#64748B', marginBottom: 6 }}>PASSWORD / AD PASSWORD</label>
            <input
              type="password"
              value={form.password}
              onChange={e => setForm({ ...form, password: e.target.value })}
              placeholder=""
              autoComplete="current-password"
              required
              style={{ width: '100%', padding: '12px 14px', border: '1px solid #E2E8F0', borderRadius: 10, fontSize: 14, fontFamily: 'Georgia, serif', outline: 'none', boxSizing: 'border-box' }}
            />
          </div>

          {error && (
            <div style={{ background: '#FEF2F2', border: '1px solid #FECACA', borderRadius: 8, padding: '10px 14px', fontSize: 13, color: '#DC2626', marginBottom: 16 }}>
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={loading}
            style={{ width: '100%', padding: 14, background: loading ? '#93C5FD' : '#2563EB', color: 'white', border: 'none', borderRadius: 10, fontSize: 14, fontWeight: 700, cursor: loading ? 'default' : 'pointer', transition: 'background 0.2s' }}
          >
            {loading ? 'Signing in…' : 'Sign In with University Account'}
          </button>
        </form>

        <div style={{ marginTop: 28, padding: 16, background: '#F8FAFC', borderRadius: 10, fontSize: 12, color: '#64748B' }}>
          <div style={{ fontWeight: 700, marginBottom: 8, color: '#475569' }}>🔐 Active Directory SSO</div>
          Use your university email and AD password. First-time users can also use the credentials issued by IT.
        </div>

        <div style={{ marginTop: 24, textAlign: 'center', fontSize: 11, color: '#CBD5E1', fontFamily: 'monospace' }}>
          Powered by CloudTitans © 2026 v3.0
        </div>

      </div>
    </div>
  )
}
